INSERT INTO medconnect.feedback (id, user_id, category, rating, allow_contact, details, created_at) VALUES
                                                                                                        ('A0000000-0000-0000-0000-000000000001', '00000000-0000-0000-0000-000000000007', 'SUGGESTION', 'POSITIVE', true,  'Aplicatia este foarte utila! As vrea sa pot filtra farmaciile si dupa program (non-stop).', '2024-02-01 10:00:00'),
                                                                                                        ('A0000000-0000-0000-0000-000000000002', '00000000-0000-0000-0000-000000000008', 'BUG',        'NEGATIVE', true,  'Nu am primit emailul cu codul de ridicare dupa ce doctorul mi-a prescris reteta.',           '2024-02-05 14:30:00'),
                                                                                                        ('A0000000-0000-0000-0000-000000000003', '00000000-0000-0000-0000-000000000002', 'SUGGESTION', 'POSITIVE', false, 'Ar fi util sa pot vedea istoricul complet al unui pacient dintr-o singura pagina.',           '2024-02-10 09:15:00'),
                                                                                                        ('A0000000-0000-0000-0000-000000000004', '00000000-0000-0000-0000-000000000017', 'BUG',        'NEGATIVE', true,  'Stocul nu se actualizeaza in timp real, apar cantitati gresite dupa salvare.',              '2024-02-12 16:00:00'),
                                                                                                        ('A0000000-0000-0000-0000-000000000005', '00000000-0000-0000-0000-000000000009', 'OTHER',      'NEUTRAL',  false, 'Interfata e ok, dar as prefera si o versiune de aplicatie mobila.',                        '2024-02-15 11:30:00'),
                                                                                                        ('A0000000-0000-0000-0000-000000000006', '00000000-0000-0000-0000-000000000003', 'SUGGESTION', 'POSITIVE', true,  'Modulul de avertizare pentru interactiuni medicamentoase este excelent.',                  '2024-02-18 08:45:00'),
                                                                                                        ('A0000000-0000-0000-0000-000000000007', '00000000-0000-0000-0000-000000000010', 'BUG',        'NEGATIVE', false, 'Nu pot sa imi vizualizez alergiile in profil, pagina da eroare.',                         '2024-02-20 13:00:00'),
                                                                                                        ('A0000000-0000-0000-0000-000000000008', '00000000-0000-0000-0000-000000000018', 'SUGGESTION', 'NEUTRAL',  true,  'Ar fi util un istoric al retetelor ridicate per farmacie, nu doar per pacient.',           '2024-02-22 15:30:00'),
                                                                                                        ('A0000000-0000-0000-0000-000000000009', '00000000-0000-0000-0000-000000000004', 'OTHER',      'POSITIVE', false, 'Foarte bine ca nu pot modifica eu insami datele medicale. Ma simt in siguranta.',          '2024-02-25 10:00:00'),
                                                                                                        ('A0000000-0000-0000-0000-000000000010', '00000000-0000-0000-0000-000000000005', 'BUG',        'NEGATIVE', true,  'Codul de ridicare a fost deja marcat ca folosit desi nu am ridicat medicamentele.',       '2024-03-01 09:30:00');